const payload = $input.item.json;

const commits = payload.commits || [];
const repoName = payload.repository?.full_name || 'desconhecido';
const branch = payload.ref?.replace('refs/heads/', '') || 'main';
const pusher = payload.pusher?.name || 'Musculo';

const ultimoCommit = commits[commits.length - 1];
const mensagem = ultimoCommit?.message || 'sem mensagem';
const sha = ultimoCommit?.id?.substring(0, 7) || '0000000';

// Detectar RESOLVE
const temResolve = mensagem.includes('[RESOLVE:');
const pendente = temResolve ? mensagem.match(/\[RESOLVE:\s*([^\]]+)\]/)?.[1] : null;

return [{
  json: {
    repoName,
    branch,
    pusher,
    mensagem,
    sha,
    totalCommits: commits.length,
    temResolve,
    pendente,
    timestamp: new Date().toISOString()
  }
}];
